class Solution:
    def removeZeroSumSublists(self, head: Optional[ListNode]) -> Optional[ListNode]:
        dummy = ListNode(0)
        dummy.next = head
        curr_sum = 0
        node = dummy
        while node:
            curr_sum += node.val
            node = node.next
            while curr_sum < 0:
                curr_sum -= node.val
                node = node.next
            if curr_sum == 0:
                node = dummy
                while node.next != node:
                    node = node.next
                node.next = node.next.next
                return dummy.next
        return head

